INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES ("", 91, "", "", 13020014, "", 13020011, "", 302, "", "");
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES ("", 11, 10, "", 13020015, "いかんいかん\n資材の山に埋もれて\nしまうところだった", 111031, "", 302, "", "");
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES ("", 91, "", "", 13020016, "", 0, "", 302, "", "");
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES ("", 3, 0, 0.2, 13020017, "nyx_302_yuni_02", 2, "", 302, "NoItem", 1);
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES (0.2, 3, 0, 0.2, 13020018, "nyx_302_yuni_02", 111031, "", 302, "nyx_idle_normal", 1);
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES ("", 11, 10, "", 13020019, "だが怪我の功名、\n探していた部品を\n偶然にも発見できた", 111031, "", 302, "", "");
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES ("", 93, "", "", 13020020, "", 5, "", 302, "", "");
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES ("", 4, "", "", 13020021, 0, 111031, "", 302, "", "");
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES ("", 3, 1, 0.2, 13020022, "nyx_cmn_03", 111031, "", 302, "", "");
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES ("", 11, 10, "", 13020023, "ふむ…これは僥倖\nかくなる上は再び\n潜航してみるか…", 111031, "", 302, "", "");
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES ("", 91, "", "", 13020024, "", 0, "", 302, "", "");
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES ("", 3, 1, 0.2, 13020025, "nyx_301_yuni_01", 111031, "", 302, "", "");
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES ("", 11, 10, "", 13020026, "存外意義あるものだ\n資材ダイビングとか\nいう新種の探索行は", 111031, "", 302, "", "");
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES ("", 91, "", "", 13020027, 1, 0, "", 302, "", "");
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES ("", 11, 10, "", 13020028, "まあ万一溺れたとて\n後輩たちの誰ぞが\nきっと気付くだろう", 111031, "", 302, "", "");
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES ("", 91, "", "", 13020029, 1, 0, "", 302, "", "");
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES ("", 3, 0, 0.2, 13020030, "nyx_302_yuni_03", 111031, "", 302, "nyx_302_yuni_04", 1);
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES ("", 11, 10, "", 13020031, "是非もなし\nいざ往かん！", 111031, "", 302, "", "");
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES ("", 91, "", "", 13020032, 1, 0, "", 302, "", "");
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES ("", 93, "", "", 13020033, "", 1.5, "", 302, "", "");
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES ("", 11, 10, "", 13020034, "む。奥に入りすぎた\nこれは…出られぬ！\n誰かー！　誰か―！", 111031, "", 302, "", "");
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES ("", 91, "", "", 13020035, "", 0, "", 302, "", "");
